// frontend/src/pages/SplashPage.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './SplashPage.css';

const SplashPage = () => {
  const navigate = useNavigate();
  const [dots, setDots]         = useState('');
  const [isExiting, setIsExiting] = useState(false);

  useEffect(() => {
    // Lock body scroll while splash is active
    document.body.classList.add('splash-active');

    // Animate the dots
    const dotInterval = setInterval(() => {
      setDots(prev => (prev.length < 3 ? prev + '.' : ''));
    }, 500);

    // Begin fade-out 500ms before navigating
    const exitTimer = setTimeout(() => setIsExiting(true), 2500);

    // Navigate and unlock scroll
    const navTimer = setTimeout(() => {
      document.body.classList.remove('splash-active');
      navigate('/home');
    }, 3000);

    return () => {
      clearInterval(dotInterval);
      clearTimeout(exitTimer);
      clearTimeout(navTimer);
      document.body.classList.remove('splash-active');
    };
  }, [navigate]);

  return (
    <div className={`splash-wrapper ${isExiting ? 'fade-out' : ''}`}>
      <div className="bg-pattern" />
      <div className="loader-container">
        <div className="splash-logo">&#128506;</div>
        <h1>Museum Journal</h1>
        <p className="splash-sub">Explore. Discover. Remember.</p>
        <div className="spinner" />
        <p className="loading-text">
          Loading<span className="dots-box">{dots}</span>
        </p>
      </div>
    </div>
  );
};

export default SplashPage;
